41	const PROCESSING_FEE = 5;
42	const BLOCK_SIZE = 3;
43	const COMPONENT_UNIT_PREMIUM = 25;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const FIRST_INSURANCE_RATE = 0.1;
46	const LOYALTY_RATE = 0.2;
47	const LOYALTY_MIN_YEARS = 2;
48	const FOLLOW_UP_RATE = 0.15;
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	const DEDUCTIBLE = 100;
53	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
54	const DAMAGE_REIMBURSEMENT_RATE = 0.5;
55	
56	const CAP_MULTIPLIER = 2;
57	const COMPONENT_INSURANCE_VALUE = 250;
58	
59	const COMPONENT_TYPES = ["rune", "moonstone"];
60	
61	const BASE_PREMIUMS: Record<string, number> = {
62	  sword: 100,
63	  amulet: 60,
64	  staff: 80,
65	  potion: 40,
66	  rune: COMPONENT_UNIT_PREMIUM,
67	  moonstone: COMPONENT_UNIT_PREMIUM,
68	};
69	
70	const INSURANCE_VALUES: Record<string, number> = {
71	  sword: 1000,
72	  amulet: 600,
73	  staff: 800,
74	  potion: 400,
75	  rune: COMPONENT_INSURANCE_VALUE,
76	  moonstone: COMPONENT_INSURANCE_VALUE,
77	};
78	
79	const insuranceValueFor = (item: Item): number =>
80	  INSURANCE_VALUES[item.type] ?? 0;
81	
82	const insuranceSum = (items: Item[]): number =>
83	  sumOver(items, insuranceValueFor);
84	
85	const policyCap = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
86	
87	export const buildPolicy = (items: Item[]): Policy => ({
88	  items,
89	  remainingCap: policyCap(items),
90	});
91	
92	const isComponent = (item: Item): boolean =>
93	  COMPONENT_TYPES.includes(item.type);
94	
95	const isMainItem = (item: Item): boolean => !isComponent(item);
96	
97	const unitPriceFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
98	
99	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
100	  items.reduce((sum, item) => sum + valueOf(item), 0);
101	
102	const componentGroupPremium = (count: number): number =>
103	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
104	
105	const countByType = (items: Item[]): Map<string, number> =>
106	  items.reduce((counts, item) => {
107	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
108	    return counts;
109	  }, new Map<string, number>());
110	
111	const componentsBasePremium = (items: Item[]): number =>
112	  [...countByType(items.filter(isComponent)).values()].reduce(
113	    (sum, count) => sum + componentGroupPremium(count),
114	    0
115	  );
116	
117	const mainItemsBasePremium = (items: Item[]): number =>
118	  sumOver(items.filter(isMainItem), unitPriceFor);
119	
120	const totalBasePremium = (items: Item[]): number =>
121	  mainItemsBasePremium(items) + componentsBasePremium(items);
122	
123	const isHighlyEnchanted = (item: Item): boolean =>
124	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
125	
126	const itemSurchargeRate = (item: Item): number =>
127	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
128	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
129	
130	const itemSurcharges = (item: Item): number =>
131	  unitPriceFor(item) * itemSurchargeRate(item);
132	
133	const totalSurcharges = (items: Item[]): number =>
134	  sumOver(items, itemSurcharges);
135	
136	const firstInsuranceSurcharge = (policyBase: number): number =>
137	  policyBase * FIRST_INSURANCE_RATE;
138	
139	const isLoyal = (customer: Customer): boolean =>
140	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
141	
142	const policyBaseShareWhen = (
143	  policyBase: number,
144	  applies: boolean,
145	  rate: number
146	): number => (applies ? policyBase * rate : 0);
147	
148	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
149	  policyBaseShareWhen(policyBase, isLoyal(customer), LOYALTY_RATE);
150	
151	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
152	  policyBaseShareWhen(policyBase, isFollowUp, FOLLOW_UP_RATE);
153	
154	const policyWideAdjustment = (
155	  policyBase: number,
156	  customer: Customer,
157	  isFollowUp: boolean
158	): number =>
159	  firstInsuranceSurcharge(policyBase) -
160	  loyaltyDiscount(policyBase, customer) -
161	  followUpDiscount(policyBase, isFollowUp);
162	
163	const roundPremiumInMHPCOsFavor = (premium: number): number =>
164	  Math.ceil(premium);
165	
166	export const quote = (input: QuoteInput, context: QuoteContext = {}): number => {
167	  const policyBase = totalBasePremium(input.items);
168	  const premiumBeforeFee =
169	    policyBase +
170	    totalSurcharges(input.items) +
171	    policyWideAdjustment(policyBase, input.customer, context.isFollowUp ?? false);
172	  return roundPremiumInMHPCOsFavor(premiumBeforeFee + PROCESSING_FEE);
173	};
174	
175	const isHighEnchantmentClaim = (item: Item): boolean =>
176	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
177	
178	const reimbursedAmount = (item: Item, amount: number): number =>
179	  isHighEnchantmentClaim(item) ? amount * DAMAGE_REIMBURSEMENT_RATE : amount;
180	
181	const damagePayout = (item: Item, damage: Damage): number =>
182	  Math.max(0, reimbursedAmount(item, damage.amount) - DEDUCTIBLE);
183	
184	const damagedItem = (items: Item[], damage: Damage): Item | undefined =>
185	  items.find((item) => item.type === damage.itemType);
186	
187	const totalPayout = (policy: Policy, damages: Damage[]): number =>
188	  damages.reduce((sum, damage) => {
189	    const item = damagedItem(policy.items, damage);
190	    return sum + (item ? damagePayout(item, damage) : 0);
191	  }, 0);
192	
193	export const claim = (policy: Policy, incident: Incident): ClaimResult => {
194	  const payout = totalPayout(policy, incident.damages);
195	  return { payout, remainingCap: policy.remainingCap - payout };
196	};
